  const shouldClarifyTrainingQuestion = (query = "") => {
    const normalized = String(query || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
    if (!normalized) return false;

    if (/\b(boss|manager|owner|creator|made you|built you|teacher|professor|student|children|kids|family)\b/.test(normalized)) {
      return false;
    }

    const trainingPatterns = [
      "who is training you",
      "who s training you",
      "who trains you",
      "who trained you",
      "who is teaching you",
      "who teaches you",
      "who taught you",
      "who is guiding you",
      "who guides you",
      "who is coaching you",
      "who coaches you",
      "who is mentoring you",
      "who mentors you"
    ];

    if (!trainingPatterns.some((pattern) => normalized.includes(pattern))) {
      return false;
    }

    if (/(ai|assistant|bot|synapse|sooraj|portfolio|website|career|his|he)\b/.test(normalized)) {
      return false;
    }

    return true;
  };

  const shouldClarifyNameQuestion = (query = "") => {
    const normalized = String(query || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
    if (!normalized) return false;

    const namePatterns = [
      "what is your name",
      "whats your name",
      "what s your name",
      "your name",
      "who are you",
      "name please",
      "tell me your name",
      "can i know your name",
      "what should i call you"
    ];

    if (!namePatterns.some((pattern) => normalized.includes(pattern) || normalized === pattern)) {
      return false;
    }

    if (/\b(sooraj|owner|portfolio owner|website owner|founder|bot|assistant|ai|synapse|chatbot)\b/.test(normalized)) {
      return false;
    }

    return true;
  };

  const shouldClarifyComplianceQuestion = (query = "") => {
    const normalized = String(query || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
    if (!normalized) return false;

    const hasRuleTerms = /\b(eu|europe|european|gdpr|dsgvo|ai act|a i act|eprivacy|privacy law|privacy laws|article 50|article 13|article 15|article 17|article 32|chatbot law|chatbot laws|chatbot rules|chatbot guideline|chatbot guidelines|regulation|regulations|compliance|guideline|guidelines|rule|rules|law|laws|germany|german)\b/.test(normalized);
    const hasFollowTerms = /\b(follow|follows|following|comply|compliant|compliance|aligned|legal|lawful|regulated|regulation)\b/.test(normalized);
    const hasAssistantTerms = /\b(ai|assistant|bot|chatbot|website|chat|synapse)\b/.test(normalized);

    return hasRuleTerms && (hasFollowTerms || /\b(article|gdpr|dsgvo|ai act|eprivacy)\b/.test(normalized)) && !hasAssistantTerms;
  };

  const isBotNameQuestionDuringNameCapture = (query = "") => {
    const normalized = String(query || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
    if (!normalized) return false;

    const directPatterns = [
      "what is your name",
      "whats your name",
      "what s your name",
      "your name",
      "who are you",
      "tell me your name",
      "name please",
      "what should i call you",
      "what can i call you",
      "may i know your name",
      "can i know your name"
    ];
    const asksForName = directPatterns.some((pattern) => normalized.includes(pattern) || normalized === pattern);
    const mentionsBot = /\b(ai|assistant|bot|chatbot|synapse)\b/.test(normalized);
    const mentionsOwner = /\b(sooraj|owner|website owner|portfolio owner|founder|his name|her name)\b/.test(normalized)
      || HELP_BOT_OWNER_PATTERN.test(normalized);

    return !mentionsOwner && (asksForName || (mentionsBot && /\b(name|who are you)\b/.test(normalized)));
  };

  const detectHelpBotPersonalIdentityIntent = (query = "") => {
    const normalized = String(query || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
    if (!normalized) return null;

    const mentionsOwner = HELP_BOT_OWNER_PATTERN.test(normalized);
    const mentionsAssistant = /\b(ai|assistant|bot|synapse|chatbot)\b/.test(normalized);
    const usesYouPronoun = /\b(you|your|yours|you re|you are)\b/.test(normalized);
    const asksForDocumentNumber = /\b(passport number|visa number|permit number|document number|id number|expiry|expiration|expire|valid until)\b/.test(normalized);

    const hasAgeIntent = /\b(how old|age|old are you|old is sooraj|birthday|date of birth|dob|born when|when was .* born)\b/.test(normalized)
      || (/\bwhen\b/.test(normalized) && /\bborn\b/.test(normalized));
    const hasOriginIntent = /\b(where are .* from|where is .* from|from where|are you from|is .* from|born in|which state|what state|where was .* born|origin|hometown|originally from|come from|comes from|native place|native country)\b/.test(normalized);
    const hasLocationIntent = /\b(where do .* live|where does .* live|where do .* work|where does .* work|where is .* now|currently in|current location|living now|working now|do you live in|does .* live in|are you in germany|are you in stuttgart|based in|current place of living|place of living|current base)\b/.test(normalized);
    const hasNationalityIntent = !asksForDocumentNumber
      && /\b(nationality|citizenship|citizen|passport|passport holder|indian)\b/.test(normalized);
    const isComplimentStyleGenderPhrase = /\b(good|nice|sweet|cute|lovely|smart|helpful|funny|cool|great|best|dear)\s+(boy|girl|man|woman)\b/.test(normalized);
    const hasGenderIntent = !isComplimentStyleGenderPhrase
      && /\b(gender|sex|male|female|boy|girl|man|woman|he or she|she or he|boy or girl|girl or boy|man or woman|woman or man|male or female|female or male)\b/.test(normalized)
      && /\b(are|is|what|which|tell|say|identify|gender|sex|boy|girl|man|woman)\b/.test(normalized);
    const hasRelationshipIntent = /\b(single|married|relationship status|wife|husband|girlfriend|boyfriend)\b/.test(normalized);
    const hasPermitIntent = !asksForDocumentNumber
      && /\b(work permit|visa|schengen|work authorization|residence permit)\b/.test(normalized);
    const hasLanguageIntent = (
      /\b(language|languages|langauges|lanaguages|langauge|english|malayalam|malaylam|german|deutsch)\b/.test(normalized)
      && /\b(speak|speaks|spoken|know|knows|talk|talks|use|uses|can|does|do|which|what|level)\b/.test(normalized)
    ) || /\b(do you speak|can you speak|what do you speak|which languages|what languages)\b/.test(normalized);
    const hasOverviewIntent = /\b(personal details|personal detail|owner details|details about sooraj|about sooraj|tell me about sooraj)\b/.test(normalized);

    const matchedCategories = [
      hasAgeIntent ? "age" : "",
      hasOriginIntent ? "origin" : "",
      hasLocationIntent ? "location" : "",
      hasNationalityIntent ? "nationality" : "",
      hasGenderIntent ? "gender" : "",
      hasRelationshipIntent ? "relationship" : "",
      hasPermitIntent ? "permit" : "",
      hasLanguageIntent ? "language" : ""
    ].filter(Boolean);

    let category = "";
    if (hasOverviewIntent || matchedCategories.length > 1) category = "overview";
    else category = matchedCategories[0] || "";
    if (!category) return null;

    if (mentionsOwner && !mentionsAssistant) {
      return { target: "owner", category };
    }
    if (mentionsAssistant && !mentionsOwner) {
      return { target: "assistant", category };
    }
    if (usesYouPronoun && !mentionsOwner && !mentionsAssistant) {
      return { target: "clarify", category };
    }
    if (hasOverviewIntent) {
      return { target: "owner", category };
    }
    return null;
  };

  const detectHelpBotGermanLanguageIntent = (query = "") => {
    const normalized = String(query || "")
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, " ")
      .trim();
    if (!normalized) return null;

    const mentionsOwner = HELP_BOT_OWNER_PATTERN.test(normalized);
    const mentionsAssistant = /\b(ai|assistant|bot|synapse|chatbot)\b/.test(normalized);
    const usesYouPronoun = /\b(you|your|you re|you are|du|dein|deine|dir)\b/.test(normalized);
    const asksAboutGerman = /\b(german|deutsch)\b/.test(normalized)
      && /\b(speak|speaking|talk|chat|write|understand|translate|antworten|sprechen|schreiben|chatten|uebersetzen|ubersetzen|kannst|sprichst)\b/.test(normalized);

    if (!asksAboutGerman) return null;
    if (mentionsOwner && !mentionsAssistant) return { target: "owner" };
    if (mentionsAssistant && !mentionsOwner) return { target: "assistant" };
    if (usesYouPronoun && !mentionsOwner && !mentionsAssistant) return { target: "clarify" };
    return { target: "clarify" };
  };

  const shouldHandleConfidentialSuggestionFollowup = (query = "", previousAnswerId = "") => {
    if (previousAnswerId !== "password-request" && previousAnswerId !== "confidential-followup") {
      return false;
    }

    const normalized = normalizeReviewLookupText(query);
    if (!normalized) return false;

    const followupPatterns = [
      "why you suggest me",
      "why did you suggest",
      "why are you suggesting",
      "why do you suggest",
      "then why you suggest",
      "why did you show that",
      "why did you suggest that",
      "why you show me this",
      "why recommend that"
    ];

    return followupPatterns.some((pattern) => normalized.includes(pattern));
  };

